// networkModule.js
// React Native Networking Module for API and IoT Device Communication

const API_BASE_URL = 'https://api.example.com';
const DEFAULT_TIMEOUT = 10000;
const IOT_TIMEOUT = 5000;

// Token storage (in production, use secure storage like react-native-keychain)
let authToken = null;
let refreshToken = null;

// ==================== Configuration ====================

const defaultHeaders = {
  'Content-Type': 'application/json',
  'Accept': 'application/json',
  'X-Client-Platform': 'react-native',
  'X-Client-Version': '1.0.0',
};

const iotDefaultHeaders = {
  'Content-Type': 'application/json',
  'Accept': 'application/json',
};

// ==================== Token Management ====================

export const setAuthToken = (token) => {
  authToken = token;
};

export const setRefreshToken = (token) => {
  refreshToken = token;
};

export const clearTokens = () => {
  authToken = null;
  refreshToken = null;
};

const getAuthHeaders = () => {
  if (authToken) {
    return { 'Authorization': `Bearer ${authToken}` };
  }
  return {};
};

// ==================== Timeout Wrapper ====================

const fetchWithTimeout = (url, options, timeout = DEFAULT_TIMEOUT) => {
  return new Promise((resolve, reject) => {
    const controller = new AbortController();
    const { signal } = controller;

    const timeoutId = setTimeout(() => {
      controller.abort();
      reject(new NetworkError('Request timed out', 'TIMEOUT', url));
    }, timeout);

    fetch(url, { ...options, signal })
      .then((response) => {
        clearTimeout(timeoutId);
        resolve(response);
      })
      .catch((error) => {
        clearTimeout(timeoutId);
        if (error.name === 'AbortError') {
          reject(new NetworkError('Request timed out', 'TIMEOUT', url));
        } else {
          reject(error);
        }
      });
  });
};

// ==================== Custom Error Class ====================

class NetworkError extends Error {
  constructor(message, code, url, statusCode = null, responseBody = null) {
    super(message);
    this.name = 'NetworkError';
    this.code = code;
    this.url = url;
    this.statusCode = statusCode;
    this.responseBody = responseBody;
    this.timestamp = new Date().toISOString();
  }
}

// ==================== Response Parser ====================

const parseResponse = async (response, url) => {
  const contentType = response.headers.get('content-type') || '';

  let body;
  if (contentType.includes('application/json')) {
    try {
      body = await response.json();
    } catch (e) {
      body = await response.text();
    }
  } else if (contentType.includes('text/')) {
    body = await response.text();
  } else {
    try {
      body = await response.json();
    } catch (e) {
      body = await response.text();
    }
  }

  if (!response.ok) {
    throw new NetworkError(
      body?.message || body?.error || `HTTP ${response.status}: ${response.statusText}`,
      'HTTP_ERROR',
      url,
      response.status,
      body
    );
  }

  return {
    data: body,
    status: response.status,
    headers: response.headers,
    ok: response.ok,
  };
};

// ==================== Retry Logic ====================

const retryRequest = async (requestFn, maxRetries = 3, retryDelay = 1000) => {
  let lastError;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await requestFn();
    } catch (error) {
      lastError = error;

      // Don't retry on client errors (4xx) except 408, 429
      if (
        error.statusCode &&
        error.statusCode >= 400 &&
        error.statusCode < 500 &&
        error.statusCode !== 408 &&
        error.statusCode !== 429
      ) {
        throw error;
      }

      if (attempt < maxRetries) {
        const delay = retryDelay * Math.pow(2, attempt) + Math.random() * 500;
        console.log(
          `[NetworkModule] Retry attempt ${attempt + 1}/${maxRetries} after ${Math.round(delay)}ms`
        );
        await new Promise((resolve) => setTimeout(resolve, delay));
      }
    }
  }

  throw lastError;
};

// ==================== Token Refresh ====================

let isRefreshing = false;
let refreshSubscribers = [];

const onTokenRefreshed = (newToken) => {
  refreshSubscribers.forEach((callback) => callback(newToken));
  refreshSubscribers = [];
};

const addRefreshSubscriber = (callback) => {
  refreshSubscribers.push(callback);
};

const refreshAuthToken = async () => {
  if (!refreshToken) {
    throw new NetworkError('No refresh token available', 'AUTH_ERROR', '');
  }

  try {
    const response = await fetch(`${API_BASE_URL}/auth/refresh`, {
      method: 'POST',
      headers: {
        ...defaultHeaders,
      },
      body: JSON.stringify({ refresh_token: refreshToken }),
    });

    const data = await response.json();

    if (!response.ok) {
      throw new NetworkError('Token refresh failed', 'AUTH_ERROR', '', response.status);
    }

    authToken = data.access_token;
    if (data.refresh_token) {
      refreshToken = data.refresh_token;
    }

    return data.access_token;
  } catch (error) {
    clearTokens();
    throw error;
  }
};

const handleTokenRefresh = async (originalRequestFn) => {
  if (isRefreshing) {
    return new Promise((resolve, reject) => {
      addRefreshSubscriber((newToken) => {
        resolve(originalRequestFn(newToken));
      });
    });
  }

  isRefreshing = true;

  try {
    const newToken = await refreshAuthToken();
    isRefreshing = false;
    onTokenRefreshed(newToken);
    return originalRequestFn(newToken);
  } catch (error) {
    isRefreshing = false;
    refreshSubscribers = [];
    throw error;
  }
};

// ==================== Request Logger ====================

const logRequest = (method, url, options) => {
  if (__DEV__) {
    console.log(`[NetworkModule] ${method} ${url}`, {
      headers: options.headers,
      body: options.body ? JSON.parse(options.body) : undefined,
    });
  }
};

const logResponse = (method, url, response, duration) => {
  if (__DEV__) {
    console.log(
      `[NetworkModule] ${method} ${url} → ${response.status} (${duration}ms)`,
      response.data
    );
  }
};

// ==================== Cloud API Module ====================

const apiRequest = async (method, endpoint, { body, headers, query, retry = true, timeout } = {}) => {
  const url = new URL(endpoint, API_BASE_URL);

  if (query) {
    Object.entries(query).forEach(([key, value]) => {
      if (value !== null && value !== undefined) {
        url.searchParams.append(key, String(value));
      }
    });
  }

  const fullUrl = url.toString();

  const makeRequest = async (token) => {
    const requestHeaders = {
      ...defaultHeaders,
      ...(token ? { 'Authorization': `Bearer ${token}` } : getAuthHeaders()),
      ...headers,
    };

    const options = {
      method,
      headers: requestHeaders,
    };

    if (body && method !== 'GET' && method !== 'HEAD') {
      options.body = JSON.stringify(body);
    }

    logRequest(method, fullUrl, options);
    const startTime = Date.now();

    const response = await fetchWithTimeout(fullUrl, options, timeout || DEFAULT_TIMEOUT);
    const parsed = await parseResponse(response, fullUrl);

    logResponse(method, fullUrl, parsed, Date.now() - startTime);
    return parsed;
  };

  const requestWithAuth = async () => {
    try {
      return await makeRequest();
    } catch (error) {
      if (error.statusCode === 401 && refreshToken) {
        return handleTokenRefresh((newToken) => makeRequest(newToken));
      }
      throw error;
    }
  };

  if (retry) {
    return retryRequest(requestWithAuth);
  }

  return requestWithAuth();
};

export const api = {
  get: (endpoint, options) => apiRequest('GET', endpoint, options),
  post: (endpoint, body, options) => apiRequest('POST', endpoint, { ...options, body }),
  put: (endpoint, body, options) => apiRequest('PUT', endpoint, { ...options, body }),
  patch: (endpoint, body, options) => apiRequest('PATCH', endpoint, { ...options, body }),
  delete: (endpoint, options) => apiRequest('DELETE', endpoint, options),
};

// ==================== IoT Device Module ====================

class IoTDeviceConnection {
  constructor(ipAddress, { port = 80, useHttps = false, deviceId = null, authKey = null } = {}) {
    this.ipAddress = ipAddress;
    this.port = port;
    this.protocol = useHttps ? 'https' : 'http';
    this.baseUrl = `${this.protocol}://${ipAddress}:${port}`;
    this.deviceId = deviceId;
    this.authKey = authKey;
    this.isReachable = false;
    this.lastSeen = null;
    this.deviceInfo = null;
  }

  getHeaders() {
    const headers = { ...iotDefaultHeaders };
    if (this.authKey) {
      headers['X-Device-Auth'] = this.authKey;
    }
    if (this.deviceId) {
      headers['X-Device-Id'] = this.deviceId;
    }
    return headers;
  }

  async request(method, path, { body, headers, timeout, retry = false } = {}) {
    const url = `${this.baseUrl}${path}`;

    const requestHeaders = {
      ...this.getHeaders(),
      ...headers,
    };

    const options = {
      method,
      headers: requestHeaders,
    };

    if (body && method !== 'GET' && method !== 'HEAD') {
      options.body = JSON.stringify(body);
    }

    logRequest(method, url, options);
    const startTime = Date.now();

    const makeRequest = async () => {
      try {
        const response = await fetchWithTimeout(url, options, timeout || IOT_TIMEOUT);
        const parsed = await parseResponse(response, url);
        this.isReachable = true;
        this.lastSeen = new Date();
        logResponse(method, url, parsed, Date.now() - startTime);
        return parsed;
      } catch (error) {
        if (error.code === 'TIMEOUT') {
          this.isReachable = false;
        }
        throw new NetworkError(
          `IoT device ${this.ipAddress}: ${error.message}`,
          error.code || 'IOT_ERROR',
          url,
          error.statusCode,
          error.responseBody
        );
      }
    };

    if (retry) {
      return retryRequest(makeRequest, 2, 500);
    }

    return makeRequest();
  }

  // Convenience methods
  get(path, options) {
    return this.request('GET', path, options);
  }

  post(path, body, options) {
    return this.request('POST', path, { ...options, body });
  }

  put(path, body, options) {
    return this.request('PUT', path, { ...options, body });
  }

  delete(path, options) {
    return this.request('DELETE', path, options);
  }

  // IoT-specific methods
  async ping() {
    try {
      const startTime = Date.now();
      await this.get('/ping', { timeout: 3000 });
      const latency = Date.now() - startTime;
      this.isReachable = true;
      this.lastSeen = new Date();
      return { reachable: true, latency };
    } catch (error) {
      this.isReachable = false;
      return { reachable: false, latency: null, error: error.message };
    }
  }

  async getDeviceInfo() {
    const response = await this.get('/device/info', { retry: true });
    this.deviceInfo = response.data;
    return response.data;
  }

  async getStatus() {
    return this.get('/status');
  }

  async sendCommand(command, params = {}) {
    return this.post('/command', { command, params });
  }

  async updateFirmware(firmwareUrl) {
    return this.post('/firmware/update', { url: firmwareUrl }, { timeout: 30000 });
  }

  async getSettings() {
    return this.get('/settings');
  }

  async updateSettings(settings) {
    return this.put('/settings', settings);
  }

  async reboot() {
    return this.post('/device/reboot', {}, { timeout: 3000 });
  }

  async factoryReset() {
    return this.post('/device/factory-reset', {});
  }

  async getSensorData(sensorType = null) {
    const path = sensorType ? `/sensors/${sensorType}` : '/sensors';
    return this.get(path);
  }
}

// ==================== IoT Device Manager ====================

class IoTDeviceManager {
  constructor() {
    this.devices = new Map();
    this.discoveryCallbacks = [];
  }

  addDevice(ipAddress, options = {}) {
    const key = `${ipAddress}:${options.port || 80}`;
    if (this.devices.has(key)) {
      return this.devices.get(key);
    }
    const device = new IoTDeviceConnection(ipAddress, options);
    this.devices.set(key, device);
    return device;
  }

  removeDevice(ipAddress, port = 80) {
    const key = `${ipAddress}:${port}`;
    this.devices.delete(key);
  }

  getDevice(ipAddress, port = 80) {
    const key = `${ipAddress}:${port}`;
    return this.devices.get(key) || null;
  }

  getAllDevices() {
    return Array.from(this.devices.values());
  }

  getReachableDevices() {
    return this.getAllDevices().filter((device) => device.isReachable);
  }

  async pingAll() {
    const results = await Promise.allSettled(
      this.getAllDevices().map(async (device) => {
        const result = await device.ping();
        return {
          ip: device.ipAddress,
          port: device.port,
          deviceId: device.deviceId,
          ...result,
        };
      })
    );

    return results.map((result) => {
      if (result.status === 'fulfilled') {
        return result.value;
      }
      return {
        reachable: false,
        error: result.reason.message,
      };
    });
  }

  async discoverDevices(subnet = '192.168.1', portRange = [80], timeout = 2000) {
    console.log(`[IoTManager] Scanning subnet ${subnet}.0/24...`);

    const scanPromises = [];

    for (let i = 1; i <= 254; i++) {
      const ip = `${subnet}.${i}`;
      for (const port of portRange) {
        scanPromises.push(this.probeDevice(ip, port, timeout));
      }
    }

    // Process in batches to avoid overwhelming the network
    const batchSize = 20;
    const discoveredDevices = [];

    for (let i = 0; i < scanPromises.length; i += batchSize) {
      const batch = scanPromises.slice(i, i + batchSize);
      const results = await Promise.allSettled(batch);

      results.forEach((result) => {
        if (result.status === 'fulfilled' && result.value) {
          discoveredDevices.push(result.value);
        }
      });
    }

    console.log(`[IoTManager] Discovered ${discoveredDevices.length} devices`);
    return discoveredDevices;
  }

  async probeDevice(ip, port, timeout) {
    const url = `http://${ip}:${port}/ping`;
    try {
      const response = await fetchWithTimeout(
        url,
        {
          method: 'GET',
          headers: iotDefaultHeaders,
        },
        timeout
      );

      if (response.ok) {
        let data;
        try {
          data = await response.json();
        } catch (e) {
          data = {};
        }

        const device = this.addDevice(ip, {
          port,
          deviceId: data.device_id || null,
        });
        device.isReachable = true;
        device.lastSeen = new Date();
        device.deviceInfo = data;

        return {
          ip,
          port,
          deviceId: data.device_id,
          deviceType: data.device_type,
          data,
        };
      }
      return null;
    } catch (error) {
      return null;
    }
  }

  async broadcastCommand(command, params = {}) {
    const reachableDevices = this.getReachableDevices();
    const results = await Promise.allSettled(
      reachableDevices.map(async (device) => {
        const result = await device.sendCommand(command, params);
        return {
          ip: device.ipAddress,
          deviceId: device.deviceId,
          ...result,
        };
      })
    );

    return results.map((result, index) => {
      if (result.status === 'fulfilled') {
        return { success: true, ...result.value };
      }
      return {
        success: false,
        ip: reachableDevices[index].ipAddress,
        error: result.reason.message,
      };
    });
  }
}

// ==================== Upload/Download Helpers ====================

export const uploadFile = async (endpoint, fileUri, {
  fieldName = 'file',
  fileName = 'upload',
  mimeType = 'application/octet-stream',
  additionalFields = {},
  onProgress = null,
  headers = {},
} = {}) => {
  const url = `${API_BASE_URL}${endpoint}`;

  const formData = new FormData();
  formData.append(fieldName, {
    uri: fileUri,
    type: mimeType,
    name: fileName,
  });

  Object.entries(additionalFields).forEach(([key, value]) => {
    formData.append(key, value);
  });

  const requestHeaders = {
    ...getAuthHeaders(),
    'Accept': 'application/json',
    ...headers,
    // Note: Don't set Content-Type for FormData; fetch sets it automatically with boundary
  };

  if (onProgress && typeof XMLHttpRequest !== 'undefined') {
    return new Promise((resolve, reject) => {
      const xhr = new XMLHttpRequest();

      xhr.upload.addEventListener('progress', (event) => {
        if (event.lengthComputable) {
          onProgress({
            loaded: event.loaded,
            total: event.total,
            progress: event.loaded / event.total,
          });
        }
      });

      xhr.addEventListener('load', () => {
        try {
          const data = JSON.parse(xhr.responseText);
          if (xhr.status >= 200 && xhr.status < 300) {
            resolve({ data, status: xhr.status, ok: true });
          } else {
            reject(
              new NetworkError(
                data.message || `Upload failed with status ${xhr.status}`,
                'HTTP_ERROR',
                url,
                xhr.status,
                data
              )
            );
          }
        } catch (e) {
          reject(new NetworkError('Failed to parse upload response', 'PARSE_ERROR', url));
        }
      });

      xhr.addEventListener('error', () => {
        reject(new NetworkError('Upload failed', 'NETWORK_ERROR', url));
      });

      xhr.addEventListener('timeout', () => {
        reject(new NetworkError('Upload timed out', 'TIMEOUT', url));
      });

      xhr.open('POST', url);

      Object.entries(requestHeaders).forEach(([key, value]) => {
        xhr.setRequestHeader(key, value);
      });

      xhr.timeout = 120000; // 2 minute timeout for uploads
      xhr.send(formData);
    });
  }

  const response = await fetch(url, {
    method: 'POST',
    headers: requestHeaders,
    body: formData,
  });

  return parseResponse(response, url);
};

export const downloadFile = async (endpoint, { headers = {}, timeout = 60000 } = {}) => {
  const url = `${API_BASE_URL}${endpoint}`;

  const requestHeaders = {
    ...getAuthHeaders(),
    ...headers,
  };

  const response = await fetchWithTimeout(
    url,
    {
      method: 'GET',
      headers: requestHeaders,
    },
    timeout
  );

  if (!response.ok) {
    throw new NetworkError(
      `Download failed with status ${response.status}`,
      'HTTP_ERROR',
      url,
      response.status
    );
  }

  const blob = await response.blob();
  return {
    blob,
    contentType: response.headers.get('content-type'),
    contentLength: response.headers.get('content-length'),
    fileName: extractFileName(response.headers.get('content-disposition')),
    status: response.status,
  };
};

const extractFileName = (contentDisposition) => {
  if (!contentDisposition) return null;
  const match = contentDisposition.match(/filename[^;=\n]*=((['"]).*?\2|[^;\n]*)/);
  if (match && match[1]) {
    return match[1].replace(/['"]/g, '');
  }
  return null;
};

// ==================== WebSocket for IoT Real-time ====================

class IoTWebSocketConnection {
  constructor(ipAddress, port = 81, { path = '/ws', protocols = [], authKey = null } = {}) {
    this.url = `ws://${ipAddress}:${port}${path}`;
    this.protocols = protocols;
    this.authKey = authKey;
    this.ws = null;
    this.listeners = new Map();
    this.reconnectAttempts = 0;
    this.maxReconnectAttempts = 5;
    this.reconnectDelay = 1000;
    this.shouldReconnect = true;
    this.messageQueue = [];
    this.isConnected = false;
  }

  connect() {
    return new Promise((resolve, reject) => {
      try {
        this.ws = new WebSocket(this.url, this.protocols);

        this.ws.onopen = () => {
          console.log(`[IoTWebSocket] Connected to ${this.url}`);
          this.isConnected = true;
          this.reconnectAttempts = 0;

          // Send auth if needed
          if (this.authKey) {
            this.send({ type: 'auth', key: this.authKey });
          }

          // Flush queued messages
          while (this.messageQueue.length > 0) {
            const msg = this.messageQueue.shift();
            this.ws.send(JSON.stringify(msg));
          }

          this.emit('connected');
          resolve();
        };

        this.ws.onmessage = (event) => {
          try {
            const data = JSON.parse(event.data);
            this.emit('message', data);

            if (data.type) {
              this.emit(data.type, data);
            }
          } catch (e) {
            this.emit('raw_message', event.data);
          }
        };

        this.ws.onerror = (error) => {
          console.error(`[IoTWebSocket] Error:`, error.message);
          this.emit('error', error);
          if (!this.isConnected) {
            reject(error);
          }
        };

        this.ws.onclose = (event) => {
          console.log(`[IoTWebSocket] Disconnected from ${this.url} (code: ${event.code})`);
          this.isConnected = false;
          this.emit('disconnected', { code: event.code, reason: event.reason });

          if (this.shouldReconnect && this.reconnectAttempts < this.maxReconnectAttempts) {
            this.scheduleReconnect();
          }
        };
      } catch (error) {
        reject(error);
      }
    });
  }

  scheduleReconnect() {
    const delay = this.reconnectDelay * Math.pow(2, this.reconnectAttempts);
    this.reconnectAttempts++;
    console.log(
      `[IoTWebSocket] Reconnecting in ${delay}ms (attempt ${this.reconnectAttempts}/${this.maxReconnectAttempts})`
    );

    setTimeout(() => {
      this.connect().catch(() => {
        // Reconnect failed, will be retried
      });
    }, delay);
  }

  send(data) {
    const message = typeof data === 'string' ? data : JSON.stringify(data);

    if (this.isConnected && this.ws && this.ws.readyState === WebSocket.OPEN) {
      this.ws.send(message);
    } else {
      this.messageQueue.push(data);
    }
  }

  on(event, callback) {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event).push(callback);
    return () => this.off(event, callback);
  }

  off(event, callback) {
    if (this.listeners.has(event)) {
      const callbacks = this.listeners.get(event);
      const index = callbacks.indexOf(callback);
      if (index > -1) {
        callbacks.splice(index, 1);
      }
    }
  }

  emit(event, data) {
    if (this.listeners.has(event)) {
      this.listeners.get(event).forEach((callback) => callback(data));
    }
  }

  disconnect() {
    this.shouldReconnect = false;
    if (this.ws) {
      this.ws.close(1000, 'Client disconnect');
      this.ws = null;
    }
    this.isConnected = false;
    this.listeners.clear();
    this.messageQueue = [];
  }
}

// ==================== Health Check ====================

export const checkApiHealth = async () => {
  try {
    const startTime = Date.now();
    const response = await fetchWithTimeout(
      `${API_BASE_URL}/health`,
      {
        method: 'GET',
        headers: defaultHeaders,
      },
      5000
    );
    const latency = Date.now() - startTime;
    const data = await response.json();

    return {
      healthy: response.ok,
      latency,
      status: response.status,
      data,
    };
  } catch (error) {
    return {
      healthy: false,
      latency: null,
      error: error.message,
    };
  }
};

// ==================== Request Interceptors ====================

class InterceptorManager {
  constructor() {
    this.requestInterceptors = [];
    this.responseInterceptors = [];
  }

  addRequestInterceptor(onFulfilled, onRejected) {
    const id = this.requestInterceptors.length;
    this.requestInterceptors.push({ onFulfilled, onRejected, id });
    return id;
  }

  addResponseInterceptor(onFulfilled, onRejected) {
    const id = this.responseInterceptors.length;
    this.responseInterceptors.push({ onFulfilled, onRejected, id });
    return id;
  }

  removeRequestInterceptor(id) {
    this.requestInterceptors = this.requestInterceptors.filter((i) => i.id !== id);
  }

  removeResponseInterceptor(id) {
    this.responseInterceptors = this.responseInterceptors.filter((i) => i.id !== id);
  }

  async runRequestInterceptors(config) {
    let currentConfig = config;
    for (const interceptor of this.requestInterceptors) {
      try {
        currentConfig = await interceptor.onFulfilled(currentConfig);
      } catch (error) {
        if (interceptor.onRejected) {
          currentConfig = await interceptor.onRejected(error);
        } else {
          throw error;
        }
      }
    }
    return currentConfig;
  }

  async runResponseInterceptors(response) {
    let currentResponse = response;
    for (const interceptor of this.responseInterceptors) {
      try {
        currentResponse = await interceptor.onFulfilled(currentResponse);
      } catch (error) {
        if (interceptor.onRejected) {
          currentResponse = await interceptor.onRejected(error);
        } else {
          throw error;
        }
      }
    }
    return currentResponse;
  }
}

// ==================== Singleton Instances ====================

export const iotManager = new IoTDeviceManager();
export const interceptors = new InterceptorManager();

